  (() => {
    let text = $json.output || '';
    text = text.replace(/\r\n/g, '\n')
               .replace(/\*\*(.*?)\*\*/g, '*$1*');

    const MAX = 1900;
    const MAX_MSGS = 5;

    const splitByWords = (str, max) => {
      const res = [];
      const words = String(str).split(/\s+/);
      let buf = '';
      for (const w of words) {
        if (!buf) buf = w;
        else if ((buf + ' ' + w).length <= max) buf += ' ' + w;
        else { res.push(buf); buf = w; }
      }
      if (buf) res.push(buf);
      return res;
    };

    const paragraphs = text.split(/\n\s*\n+/).map(p => p.trim()).filter(Boolean);

    const parts = [];
    for (const p of paragraphs) {
      if (p.length <= MAX) parts.push(p);
      else parts.push(...splitByWords(p, MAX));
    }

    if (parts.length <= MAX_MSGS) return parts;

    const packed = [];
    let buf = '';
    for (const piece of parts) {
      const cand = buf ? buf + '\n\n' + piece : piece;
      if (cand.length <= MAX) buf = cand;
      else { if (buf) packed.push(buf); buf = piece; }
    }
    if (buf) packed.push(buf);
    if (packed.length <= MAX_MSGS) return packed;

    const all = parts.join('\n\n');
    return splitByWords(all, MAX).slice(0, MAX_MSGS);
  })()
}}

